// Batch trigger: set first topic to 'audio', rest to 'queued'
const topicIds = $input.first().json.body.topic_ids || [];
if (!topicIds.length) {
  return [{ json: { error: 'No topic_ids provided', topic_ids: [] } }];
}

// First topic starts immediately, rest queued
return [{
  json: {
    first_topic_id: topicIds[0],
    queued_topic_ids: topicIds.slice(1),
    all_topic_ids: topicIds
  }
}];

// Determine resume stage from last production_log entry
const logEntry = $input.first().json;
const topicId = $('Webhook Resume').item.json.body.topic_id;

let resumeStage = 'audio';
let webhookPath = 'production/tts';

if (logEntry && logEntry.stage) {
  const lastStage = logEntry.stage;
  switch (lastStage) {
    case 'audio':
      resumeStage = 'audio';
      webhookPath = 'production/tts';
      break;
    case 'images':
      resumeStage = 'images';
      webhookPath = 'production/images';
      break;
    case 'i2v':
      resumeStage = 'images';
      webhookPath = 'production/i2v';
      break;
    case 't2v':
      resumeStage = 'images';
      webhookPath = 'production/t2v';
      break;
    case 'assembly':
      resumeStage = 'assembling';
      webhookPath = 'production/assemble';
      break;
    default:
      resumeStage = 'audio';
      webhookPath = 'production/tts';
  }
}

return [{
  json: {
    topic_id: topicId,
    resume_stage: resumeStage,
    webhook_path: webhookPath
  }
}];

// Determine which stage failed and reset it
const scene = $input.first().json;
if (!scene || !scene.id) {
  return [{ json: { error: 'Scene not found' } }];
}
const resetFields = {};
let failedStage = '';

if (scene.audio_status === 'failed') {
  resetFields.audio_status = 'pending';
  failedStage = 'tts';
} else if (scene.image_status === 'failed') {
  resetFields.image_status = 'pending';
  failedStage = 'images';
} else if (scene.video_status === 'failed') {
  resetFields.video_status = 'pending';
  failedStage = scene.visual_type === 'i2v' ? 'i2v' : 't2v';
} else if (scene.clip_status === 'failed') {
  resetFields.clip_status = 'pending';
  failedStage = 'assembly';
}

return [{
  json: {
    scene_id: scene.id,
    topic_id: scene.topic_id,
    scene_number: scene.scene_number,
    visual_type: scene.visual_type,
    failed_stage: failedStage,
    reset_fields: resetFields
  }
}];

// Reset all failed statuses to pending
const allItems = $input.all().filter(item => item.json.id);
if (allItems.length === 0) {
  return [{ json: { count: 0, scene_ids: [] } }];
}

const sceneIds = allItems.map(item => item.json.id);
return [{ json: { count: allItems.length, scene_ids: sceneIds, topic_id: $('Webhook Retry All Failed').item.json.body.topic_id } }];

const topic = $('Fetch Topic').first().json;
const topicFolderId = $('Create Topic Folder').first().json.id;

return [{
  json: {
    topic_id: topic.id,
    project_id: topic.project_id,
    topic_number: topic.topic_number,
    title: topic.seo_title || topic.original_title || 'Topic',
    drive_folder_id: topicFolderId,
    drive_subfolder_ids: {
      audio: $('Create Audio Subfolder').first().json.id,
      images: $('Create Images Subfolder').first().json.id,
      video_clips: $('Create VideoClips Subfolder').first().json.id,
      captions: $('Create Captions Subfolder').first().json.id,
      final: $('Create Final Subfolder').first().json.id
    }
  }
}];
